import { createAgent, defineAgentProfile, type FlueContext } from '@flue/runtime'
import * as v from 'valibot'
import research from '../skills/research/SKILL.md' with { type: 'skill' }
import { webSearch } from '../tools/search.ts'

const searcher = defineAgentProfile({
  name: 'searcher',
  description: 'Runs web searches for a single sub-question.',
  instructions: 'Search the web for the sub-question and return findings with source URLs.',
})

const evaluator = defineAgentProfile({
  name: 'evaluator',
  description: 'Decides whether the findings answer the question.',
  instructions: 'List remaining gaps and decide if another round is needed.',
})

const orchestrator = createAgent(() => ({
  model: 'anthropic/claude-sonnet-4-6',
  skills: [research],
  tools: [webSearch],
  subagents: [searcher, evaluator],
}))

const Answer = v.object({
  answer: v.string(),
  citations: v.array(v.object({
    claim: v.string(),
    url: v.string(),
  })),
  unverified: v.array(v.string()),
})

export async function run({ init, payload }: FlueContext<{ question: string; maxRounds?: number }>) {
  const harness = await init(orchestrator)
  const session = await harness.session()

  const response = await session.prompt(
    `Research this question and iterate until it is fully answered (max ${payload.maxRounds ?? 3} rounds): ${payload.question}`,
    { result: Answer }
  )

  return response.data
}

import { defineTool } from '@flue/runtime'
import * as v from 'valibot'

type SerpResult = { title?: string; link?: string; description?: string }

export const webSearch = defineTool({
  name: 'web_search',
  description:
    'Searches the web and returns ranked results with titles, URLs, and text snippets.',
  parameters: v.object({
    query: v.string(),
    numResults: v.optional(v.number(), 5),
  }),
  execute: async ({ query, numResults }) => {
    // Bright Data SERP API — real-time, unblocked search results, billed per
    // successful request. `brd_json=1` returns parsed JSON instead of raw HTML.
    // https://docs.brightdata.com/scraping-automation/serp-api
    const target = new URL('https://www.google.com/search')
    target.searchParams.set('q', query)
    target.searchParams.set('num', String(numResults))
    target.searchParams.set('brd_json', '1')

    const res = await fetch('https://api.brightdata.com/request', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${process.env.BRIGHTDATA_API_KEY ?? ''}`,
      },
      body: JSON.stringify({
        zone: process.env.BRIGHTDATA_SERP_ZONE ?? 'serp_api',
        url: target.toString(),
        format: 'raw',
      }),
    })

    const data = (await res.json()) as { organic?: SerpResult[] }
    return JSON.stringify(
      (data.organic ?? [])
        .slice(0, numResults)
        .map((r) => ({ title: r.title, url: r.link, text: r.description }))
    )
  },
})
